-- 使用 xpcall 安全调用函数，并捕获错误信息
---@param func function
---@vararg any @[optional]
---@return any
function M.XpCall(func, ...)
	local ret
	if func then
		ret = table.pack(xpcall(func, function(err)
			print(err)
			print(debug.traceback())
		end, ...))

		return table.unpack(ret, 2)
	end
end

-- 创建一个新的类，可以继承自另一个类
---@param super_name string @[optional]
---@vararg any @[optional]
---@return LuaClass
function M.LuaClass(super_name)
	
	local notExist = {}
	local function Index(t, k)
		local mt = getmetatable(t)
		local super = mt
		while super do
			local v = rawget(super, k)
			if v ~= nil and not rawequal(v, notExist) then
				rawset(t, k, v)
				return v
			end
			super = rawget(super, "Super")
		end

		local p = mt[k]
		if p ~= nil then
			if type(p) == "function" then
				rawset(t, k, p)
			elseif rawequal(p, notExist) then
				return nil
			end
		else
			rawset(mt, k, notExist)
		end

		return p
	end

	---@class LuaClass
	local new_class = {}
	new_class.__index = Index
	new_class.__gc = function(self)
		if not rawget(self, "__bInstance") then
			return
		end
		local mt = getmetatable(self)
		while mt do
			local func = rawget(mt, "__OnGC")
			if func then
				M.XpCall(func, self)
			end
			mt = rawget(mt, "Super")
		end
	end
	
	if super_name ~= nil then
		local success, result = pcall(require, super_name)
		if success then
			new_class.Super = result
		else
			print("Failed to load super class: " .. super_name)
		end
	end

	---@generic T
	---@param self T
	---@return T
	function new_class.New(self, ...)
		local o = {
			__bInstance = true
		}
		setmetatable(o, self)
		M.XpCall(self.__OnNew, o, ...)
		return o
	end
	return new_class
end

-- 创建一个代理函数，将目标对象和方法绑定在一起
---@generic T
---@param target T
---@param func function(target:T, ...:any) T
---@return function(...:any) T
function M.Handler(target, func)
	if target == nil or func == nil then
		error("Handler: target and func must not be nil")
