	end
end

-- 创建一个处理函数，合并参数并传递给指定的目标函数
---@generic T
---@param target T
---@param func function(target:T, ...:any)
---@vararg any @[optional]
---@return function(...:any)
function M.HandleFunc(target, func, ...)
	local param = table.pack(...)
	return function(...)
		local finalParam = {}
		for k, v in ipairs(param) do
			finalParam[k] = v		
		end
		for _, v in ipairs(table.pack(...)) do
			finalParam[#finalParam + 1] = v
		end
		func(target, table.unpack(finalParam))
	end
end

-- 按分隔符分割字符串
---@param str string
---@param delimiter string
---@return table
function M.Split(str, delimiter)
	if str == nil or str == '' or delimiter == nil then
		return {}
	end
	
	local result = {}
	for match in (str .. delimiter):gmatch("(.-)" .. delimiter) do
		result[#result + 1] = match
	end
	return result
end

-- 格式化时间戳为指定格式的时间字符串
---@param format string yyyy.MM.dd hh:mm:ss
---@param time number 时间戳秒 
function M.DateFormat(format, time)
	local date = os.date("*t", time)
	local o = {
		['(M+)'] = tostring(date.month), -- 月份
		['(d+)'] = tostring(date.day), -- 日
		['(h+)'] = tostring(date.hour), -- 小时
		['(m+)'] = tostring(date.min), -- 分
		['(s+)'] = tostring(date.sec), -- 秒
		['(q+)'] = tostring(math.floor((date.month + 2) / 3)), -- 季度
	}

	local yS, yE, str = string.find(format, "(y+)")
	if yS then
		local len = yE - yS + 1
		format = string.gsub(format, str, string.sub(tostring(date.year), 5 - len), 1)
	end
	for k, v in pairs(o) do
		yS, yE, str = string.find(format, k)
		if (yS) then
			local len = yE - yS + 1
			local reply = len == 1 and v or string.sub("0" .. v, string.len(v))
			format = string.gsub(format, str, reply, 1)
		end
	end
	return format
end

-- 将秒数转换为指定格式的时间字符串
---@param format string hh:mm:ss
---@param seconds number 时间数秒 
function M.SecondsFormat(format, seconds)
	local sign = seconds >= 0 and "" or "-"
	seconds = math.abs(seconds)
	local o = {
		'(h+)', -- 小时
		'(m+)', -- 分
		'(s+)' -- 秒
	}
	local scale = {
		3600, 60, 1
	}

	for k, v in ipairs(o) do
		local yS, yE, str = string.find(format, v)
		if (yS) then
			local len = yE - yS + 1
			local value = math.floor(seconds / scale[k])
			seconds = seconds - value * scale[k]
			local reply = len == 1 and value or string.sub("0" .. value, string.len(value))
			format = string.gsub(format, str, reply, 1)
		end
	end

	return sign .. format
end

-- 禁止直接设置全局变量，强制使用 LuaHelper.__exports 来管理全局变量
function M.DisableGlobalVariable()
	local __g = _G
	M.__exports = {}
	setmetatable(M.__exports, {
		__newindex = function(_, name, value)
			rawset(__g, name, value)
		end,

		__index = function(_, name)
			return rawget(__g, name)
		end
	})

	setmetatable(__g, {
		__newindex = function(_, name, _)
			error(string.format("Please use LuaHelper.__exports.%s to set global variable ", name), 0)
        end
	})
end

return M